/**
 * @summary List chat messages in session
 */
export const getListMessagesUrl = (
  campaignId: string,
  sessionId: string,
  params?: ListMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/campaigns/${campaignId}/sessions/${sessionId}/messages?${stringifiedParams}`
    : `/api/campaigns/${campaignId}/sessions/${sessionId}/messages`;
};

export const listMessages = async (
  campaignId: string,
  sessionId: string,
  params?: ListMessagesParams,
  options?: RequestInit,
): Promise<ChatMessage[]> => {
  return customFetch<ChatMessage[]>(
    getListMessagesUrl(campaignId, sessionId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

